const raw = $input.first().json;

// --- Edit these for your environment (no $env on n8n Cloud) ---
const TWILIO_FROM = '+18449262867';
// Phone Number SID: PN848effb3e4edce45f501bfe2e97a1e97
const COORDINATOR_SMS_TO = '+12626139986'; // coordinator cell for team alerts
const APP_URL = 'https://dev.d9588bqvrp5xs.amplifyapp.com'; // production URL when live

const lead =
  raw.body && typeof raw.body === 'object' && !Array.isArray(raw.body)
    ? raw.body
    : raw;

const fullName = String(lead.name || '').trim();
const nameParts = fullName.split(/\s+/).filter(Boolean);
const firstName = String(lead.first_name || nameParts[0] || 'Unknown').trim();
const lastName = String(
  lead.last_name || nameParts.slice(1).join(' ') || ''
).trim();
const service = String(
  lead.service_requested || lead.serviceInterest || 'General inquiry'
).trim();
const phone = String(lead.phone || '').trim();
const email = String(lead.email || '').trim();
const leadId = String(lead.lead_id || 'website-inquiry');
const message = String(lead.message || '').trim();

const emailBody = [
  `Name: ${firstName}${lastName ? ` ${lastName}` : ''}`,
  `Phone: ${phone}`,
  `Email: ${email}`,
  `Service: ${service}`,
  `Lead ID: ${leadId}`,
  '',
  'Message:',
  message,
].join('\n');

const teamSmsBody = [
  'New Nesting Place lead',
  `${firstName}${lastName ? ` ${lastName}` : ''}`,
  phone || email || 'No contact',
  `Service: ${service}`,
  `Lead ID: ${leadId}`,
].join('\n');

const momSmsBody = `Hi ${firstName}, thanks for contacting The Nesting Place. Our care coordinator will follow up within one business day. You can also continue online: ${APP_URL}/care/start`;

const smsConsent = lead.sms_consent === true || lead.sms_consent === 'true';
const canSendSms = Boolean(phone && smsConsent);

return [
  {
    json: {
      ...lead,
      first_name: firstName,
      last_name: lastName,
      email_subject: 'New Lead Received',
      email_body: emailBody,
      send_to: String(
        lead.team_notification_email ||
          lead.send_to ||
          lead.notification_email ||
          'info@nesting-place.com'
      ).trim(),
      twilio_from: TWILIO_FROM,
      coordinator_sms_to: COORDINATOR_SMS_TO,
      team_sms_body: teamSmsBody,
      mom_sms_body: momSmsBody,
      phone,
      sms_consent: smsConsent,
      can_send_sms: canSendSms,
    },
  },
];
